### 9. Implement matching utilities

Create `src/utils/matching.ts`:

```typescript
export const normalizeString = (str: string): string => {
  return str.toLowerCase().trim().replace(/[^a-z0-9\s]/g, '');
};

export const calculateMatchPercentage = (
  available: string[],
  required: string[]
): number => {
  if (required.length === 0) return 0;

  const normalizedAvailable = available.map(normalizeString);
  const normalizedRequired = required.map(normalizeString);

  const matched = normalizedRequired.filter(req =>
    normalizedAvailable.some(avail =>
      avail.includes(req) || req.includes(avail)
    )
  );

  return Math.round((matched.length / normalizedRequired.length) * 100);
};

export const findMatchedIngredients = (
  available: string[],
  required: string[]
): string[] => {
  const normalizedAvailable = available.map(normalizeString);

  return required.filter(req => {
    const normalizedReq = normalizeString(req);
    return normalizedAvailable.some(avail =>
      avail.includes(normalizedReq) || normalizedReq.includes(avail)
    );
  });
};

export const findMissingIngredients = (
  available: string[],
  required: string[]
): string[] => {
  const matched = findMatchedIngredients(available, required);
  return required.filter(req => !matched.includes(req));
};

export const removeDuplicates = (ingredients: string[]): string[] => {
  const normalized = new Map<string, string>();

  ingredients.forEach(ing => {
    const key = normalizeString(ing);
    if (!normalized.has(key)) {
      normalized.set(key, ing);
    }
  });

  return Array.from(normalized.values());
};
```

### 10. Implement meal service

Create `src/services/mealService.ts`:

```typescript
import { Meal, IngredientMatch, FilterOptions } from '../types';
import mealsData from '../data/meals.json';
import {
  calculateMatchPercentage,
  findMatchedIngredients,
  findMissingIngredients,
} from '../utils/matching';

class MealService {
  private meals: Meal[] = mealsData as Meal[];

  getRandomMeal(excludeId?: string): Meal {
    let availableMeals = this.meals;

    if (excludeId) {
      availableMeals = this.meals.filter(meal => meal.id !== excludeId);
    }

    const randomIndex = Math.floor(Math.random() * availableMeals.length);
    return availableMeals[randomIndex];
  }

  findMealsByIngredients(ingredients: string[]): IngredientMatch[] {
    if (ingredients.length === 0) return [];

    const matches: IngredientMatch[] = this.meals.map(meal => {
      const matchPercentage = calculateMatchPercentage(ingredients, meal.ingredients);
      const matchedIngredients = findMatchedIngredients(ingredients, meal.ingredients);
      const missingIngredients = findMissingIngredients(ingredients, meal.ingredients);

      return {
        meal,
        matchPercentage,
        matchedIngredients,
        missingIngredients,
      };
    });

    return matches
      .filter(match => match.matchPercentage > 0)
      .sort((a, b) => b.matchPercentage - a.matchPercentage);
  }

  filterMeals(options: FilterOptions): Meal[] {
    let filtered = [...this.meals];

    if (options.category) {
      filtered = filtered.filter(meal => meal.category === options.category);
    }

    if (options.difficulty) {
      filtered = filtered.filter(meal => meal.difficulty === options.difficulty);
    }

    if (options.prepTime) {
      filtered = filtered.filter(meal =>
        meal.prepTime && meal.prepTime <= options.prepTime!
      );
    }

    if (options.ingredients && options.ingredients.length > 0) {
      const matches = this.findMealsByIngredients(options.ingredients);
      const matchedMealIds = new Set(matches.map(m => m.meal.id));
      filtered = filtered.filter(meal => matchedMealIds.has(meal.id));
    }

    // Apply sorting
    if (options.sortBy === 'random') {
      filtered.sort(() => Math.random() - 0.5);
    } else if (options.sortBy === 'category') {
      filtered.sort((a, b) => a.category.localeCompare(b.category));
    }

    return filtered;
  }

  getAllMeals(): Meal[] {
    return [...this.meals];
  }

  getMealById(id: string): Meal | undefined {
    return this.meals.find(meal => meal.id === id);
  }

  getMealsByCategory(category: string): Meal[] {
    return this.meals.filter(meal => meal.category === category);
  }
}

export const mealService = new MealService();
```

