Create `src/stores/useAppStore.ts`:

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { User, Meal, Theme } from '../types';

interface AppStore {
  // Auth
  user: User | null;
  isAuthenticated: boolean;
  setUser: (user: User | null) => void;
  logout: () => void;

  // Theme
  theme: Theme;
  effectiveTheme: 'light' | 'dark';
  setTheme: (theme: Theme) => void;
  initializeTheme: () => void;

  // Meal
  currentMeal: Meal | null;
  lastGeneratedMealId: string | null;
  setCurrentMeal: (meal: Meal | null) => void;
  setLastGeneratedMealId: (id: string | null) => void;

  // Ingredients
  selectedIngredients: string[];
  addIngredient: (ingredient: string) => void;
  removeIngredient: (ingredient: string) => void;
  clearIngredients: () => void;
  setIngredients: (ingredients: string[]) => void;

  // UI
  isLoading: boolean;
  isSidebarOpen: boolean;
  setIsLoading: (loading: boolean) => void;
  setIsSidebarOpen: (open: boolean) => void;
  toggleSidebar: () => void;
}

export const useAppStore = create<AppStore>()(
  persist(
    (set, get) => ({
      // Auth
      user: null,
      isAuthenticated: false,
      setUser: (user) => set({ user, isAuthenticated: !!user }),
      logout: () => set({ user: null, isAuthenticated: false }),

      // Theme
      theme: 'system',
      effectiveTheme: 'light',
      setTheme: (theme) => {
        set({ theme });
        const root = document.documentElement;

        if (theme === 'dark') {
          root.classList.add('dark');
          set({ effectiveTheme: 'dark' });
        } else if (theme === 'light') {
          root.classList.remove('dark');
          set({ effectiveTheme: 'light' });
        } else {
          const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
          if (prefersDark) {
            root.classList.add('dark');
            set({ effectiveTheme: 'dark' });
          } else {
            root.classList.remove('dark');
            set({ effectiveTheme: 'light' });
          }
        }
      },
      initializeTheme: () => {
        const { theme, setTheme } = get();
        setTheme(theme);
      },

      // Meal
      currentMeal: null,
      lastGeneratedMealId: null,
      setCurrentMeal: (meal) => set({ currentMeal: meal }),
      setLastGeneratedMealId: (id) => set({ lastGeneratedMealId: id }),

      // Ingredients
      selectedIngredients: [],
      addIngredient: (ingredient) =>
        set((state) => ({
          selectedIngredients: [...state.selectedIngredients, ingredient],
        })),
      removeIngredient: (ingredient) =>
        set((state) => ({
          selectedIngredients: state.selectedIngredients.filter((i) => i !== ingredient),
        })),
      clearIngredients: () => set({ selectedIngredients: [] }),
      setIngredients: (ingredients) => set({ selectedIngredients: ingredients }),

      // UI
      isLoading: false,
      isSidebarOpen: true,
      setIsLoading: (loading) => set({ isLoading: loading }),
      setIsSidebarOpen: (open) => set({ isSidebarOpen: open }),
      toggleSidebar: () => set((state) => ({ isSidebarOpen: !state.isSidebarOpen })),
    }),
    {
      name: 'mealgen-storage',
      partialize: (state) => ({
        theme: state.theme,
        selectedIngredients: state.selectedIngredients,
      }),
    }
  )
);
```

