  matchPercentage: number;
  matchedIngredients: string[];
  missingIngredients: string[];
}

export interface FilterOptions {
  category?: Category;
  ingredients?: string[];
  difficulty?: 'easy' | 'medium' | 'hard';
  prepTime?: number;
