import { motion, AnimatePresence } from 'framer-motion';

const Sidebar = () => {
  const location = useLocation();
  const { isSidebarOpen, toggleSidebar, user } = useAppStore();

  const navItems = [
    { path: '/', icon: Home, label: 'Home' },
