            <X className="w-5 h-5" />
          </button>

          {/* Navigation */}
          <nav className="space-y-2 flex-1">
            {navItems.map(({ path, icon: Icon, label }) => {
              const isActive = location.pathname === path;
              return (
                <Link
                  key={path}
                  to={path}
                  onClick={() => window.innerWidth < 1024 && toggleSidebar()}
