interface MatchIndicatorProps {
  percentage: number;
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
}

const MatchIndicator = ({ percentage, size = 'md', showLabel = true }: MatchIndicatorProps) => {
  const getColor = (pct: number) => {
    if (pct === 100) return 'bg-green-500';
    if (pct >= 75) return 'bg-green-400';
    if (pct >= 50) return 'bg-yellow-400';
    if (pct >= 25) return 'bg-orange-400';
    return 'bg-red-400';
  };

  const sizes = {
    sm: 'w-12 h-12 text-xs',
    md: 'w-16 h-16 text-sm',
    lg: 'w-20 h-20 text-base',
  };

  return (
    <div className="flex flex-col items-center gap-1">
      <div
        className={`${sizes[size]} rounded-full ${getColor(
          percentage
        )} flex items-center justify-center text-white font-bold shadow-lg`}
      >
        {percentage}%
      </div>
      {showLabel && (
        <span className="text-xs font-medium text-white drop-shadow">Match</span>
      )}
    </div>
  );
};

export default MatchIndicator;
