import { useState, KeyboardEvent } from 'react';
import Input from '../ui/Input';
import { Plus } from 'lucide-react';
import Button from '../ui/Button';

interface IngredientInputProps {
  onAdd: (ingredient: string) => void;
  suggestions?: string[];
}

const IngredientInput = ({ onAdd, suggestions = [] }: IngredientInputProps) => {
  const [value, setValue] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);

  const filteredSuggestions = suggestions.filter(s =>
    s.toLowerCase().includes(value.toLowerCase())
  ).slice(0, 5);

  const handleAdd = () => {
    if (value.trim()) {
      onAdd(value.trim());
      setValue('');
      setShowSuggestions(false);
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleAdd();
    }
  };

  return (
    <div className="relative">
      <div className="flex gap-2">
        <div className="flex-1">
          <Input
            value={value}
            onChange={(val) => {
              setValue(val);
              setShowSuggestions(val.length > 0);
            }}
            onKeyDown={handleKeyDown}
            placeholder="Enter an ingredient..."
            onFocus={() => value.length > 0 && setShowSuggestions(true)}
          />
        </div>
        <Button onClick={handleAdd} disabled={!value.trim()}>
          <Plus className="w-4 h-4" />
        </Button>
      </div>

      {/* Suggestions */}
      {showSuggestions && filteredSuggestions.length > 0 && (
        <div className="absolute z-10 w-full mt-2 glass rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 overflow-hidden">
          {filteredSuggestions.map((suggestion, index) => (
            <button
              key={index}
              onClick={() => {
                setValue(suggestion);
                setShowSuggestions(false);
              }}
              className="w-full px-4 py-2 text-left hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors text-gray-700 dark:text-gray-300"
            >
              {suggestion}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default IngredientInput;
