import { useState, useMemo } from 'react';
import { Meal, IngredientMatch } from '../../types';
import { mealService } from '../../services/mealService';
import { useAppStore } from '../../stores/useAppStore';
import { removeDuplicates } from '../../utils/matching';
import { IngredientInput, IngredientTag } from '../../components/ingredients';
import { MealCard, MealDetailsModal, CategoryFilter } from '../../components/meal';
import Card from '../../components/ui/Card';
import EmptyState from '../../components/ui/EmptyState';
import LoadingSkeleton from '../../components/ui/LoadingSkeleton';
import { Search } from 'lucide-react';
import { AnimatePresence } from 'framer-motion';

const Ingredients = () => {
  const { selectedIngredients, addIngredient, removeIngredient } = useAppStore();
  const [selectedMeal, setSelectedMeal] = useState<Meal | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  // Get all unique ingredients from meals for suggestions
  const allIngredients = useMemo(() => {
    const ingredients = mealService.getAllMeals().flatMap(m => m.ingredients);
    return removeDuplicates(ingredients).sort();
  }, []);

  // Find matching meals
  const matches: IngredientMatch[] = useMemo(() => {
    if (selectedIngredients.length === 0) return [];
    let results = mealService.findMealsByIngredients(selectedIngredients);

    if (selectedCategory) {
      results = results.filter(m => m.meal.category === selectedCategory);
    }

    return results;
  }, [selectedIngredients, selectedCategory]);

  const handleAddIngredient = (ingredient: string) => {
    const normalized = removeDuplicates([...selectedIngredients, ingredient]);
    if (normalized.length > selectedIngredients.length) {
      addIngredient(ingredient);
    }
  };

  return (
    <div className="space-y-6">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-gray-900 dark:text-gray-100 mb-2">
          Find Meals by Ingredients
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          Enter the ingredients you have and we'll find matching recipes
        </p>
      </div>

      {/* Ingredient Input */}
      <Card>
        <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-4">
          Your Ingredients
        </h2>
        <IngredientInput
          onAdd={handleAddIngredient}
          suggestions={allIngredients}
        />

        {/* Tags */}
        {selectedIngredients.length > 0 && (
          <div className="mt-4 flex flex-wrap gap-2">
            <AnimatePresence>
              {selectedIngredients.map((ingredient) => (
                <IngredientTag
                  key={ingredient}
                  ingredient={ingredient}
                  onRemove={() => removeIngredient(ingredient)}
                />
              ))}
            </AnimatePresence>
          </div>
        )}
      </Card>

      {/* Category Filter */}
      {matches.length > 0 && (
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-4">
            Filter by Category
          </h2>
          <CategoryFilter
            selectedCategory={selectedCategory as any}
            onCategoryChange={setSelectedCategory as any}
          />
        </Card>
      )}

      {/* Results */}
      <div>
        {selectedIngredients.length === 0 ? (
          <EmptyState
            icon={<Search className="w-16 h-16" />}
            title="Start by adding ingredients"
            description="Type in the ingredients you have available and we'll show you what you can make"
          />
        ) : matches.length === 0 ? (
          <EmptyState
            icon={<Search className="w-16 h-16" />}
            title="No matches found"
            description="Try adding or removing some ingredients to find matching recipes"
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {matches.map(({ meal, matchPercentage }) => (
              <MealCard
                key={meal.id}
                meal={meal}
                showMatchIndicator
                matchPercentage={matchPercentage}
                onView={() => {
                  setSelectedMeal(meal);
                  setIsModalOpen(true);
                }}
              />
            ))}
          </div>
        )}
      </div>

      {/* Modal */}
      <MealDetailsModal
        meal={selectedMeal}
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
      />
    </div>
  );
};

export default Ingredients;
