import { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Meal } from '../../types';
import { useAppStore } from '../../stores/useAppStore';
import { getFavorites, removeFavorite as removeFavoriteAPI } from '../../services/supabase';
import { mealService } from '../../services/mealService';
import { MealCard, MealDetailsModal } from '../../components/meal';
import EmptyState from '../../components/ui/EmptyState';
import LoadingSkeleton from '../../components/ui/LoadingSkeleton';
import { Heart } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Favorites = () => {
  const { user } = useAppStore();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [selectedMeal, setSelectedMeal] = useState<Meal | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    if (!user) {
      navigate('/auth/login');
    }
  }, [user, navigate]);

  const { data: favorites, isLoading } = useQuery({
    queryKey: ['favorites', user?.id],
    queryFn: () => getFavorites(user!.id),
    enabled: !!user,
  });

  const removeMutation = useMutation({
    mutationFn: (mealId: string) => removeFavoriteAPI(user!.id, mealId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['favorites', user?.id] });
    },
  });

  const favoriteMeals = favorites?.map(fav =>
    mealService.getMealById(fav.meal_id)
  ).filter(Boolean) as Meal[];

  if (isLoading) {
