```typescript
import { useState, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Meal } from '../../types';
import { useAppStore } from '../../stores/useAppStore';
import { getHistory } from '../../services/supabase';
import { mealService } from '../../services/mealService';
import { MealCard, MealDetailsModal } from '../../components/meal';
import EmptyState from '../../components/ui/EmptyState';
import LoadingSkeleton from '../../components/ui/LoadingSkeleton';
import { History as HistoryIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const History = () => {
  const { user } = useAppStore();
  const navigate = useNavigate();
  const [selectedMeal, setSelectedMeal] = useState<Meal | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    if (!user) {
      navigate('/auth/login');
    }
  }, [user, navigate]);

  const { data: history, isLoading } = useQuery({
    queryKey: ['history', user?.id],
    queryFn: () => getHistory(user!.id, 50),
    enabled: !!user,
  });

  const historyMeals = history?.map(h => ({
    meal: mealService.getMealById(h.meal_id),
    generatedAt: h.generated_at,
  })).filter(h => h.meal) as { meal: Meal; generatedAt: string }[];

  if (isLoading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {[...Array(6)].map((_, i) => (
          <LoadingSkeleton key={i} variant="card" />
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-gray-900 dark:text-gray-100 mb-2">
          Your Meal History
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          Recently generated meals
        </p>
      </div>

      {!historyMeals || historyMeals.length === 0 ? (
        <EmptyState
          icon={<HistoryIcon className="w-16 h-16" />}
          title="No history yet"
          description="Generate some meals to see them here"
          action={{
            label: 'Generate Meal',
            onClick: () => navigate('/'),
          }}
        />
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {historyMeals.map(({ meal, generatedAt }, index) => (
            <MealCard
              key={`${meal.id}-${index}`}
              meal={meal}
              onView={() => {
                setSelectedMeal(meal);
                setIsModalOpen(true);
              }}
            />
          ))}
        </div>
      )}

      <MealDetailsModal
        meal={selectedMeal}
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
      />
    </div>
  );
};

export default History;
```

