import { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useAppStore } from '../../stores/useAppStore';
import { getAllMealsFromDB, createMeal, updateMeal, deleteMeal } from '../../services/supabase';
import { Meal } from '../../types';
import { AdminMealTable, AdminMealForm } from '../../components/admin';
import Card from '../../components/ui/Card';
import Button from '../../components/ui/Button';
import Modal from '../../components/ui/Modal';
import { Plus } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const AdminMeals = () => {
  const { user } = useAppStore();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingMeal, setEditingMeal] = useState<Meal | undefined>();

  useEffect(() => {
    if (!user?.is_admin) {
      navigate('/');
    }
  }, [user, navigate]);

  const { data: meals, isLoading } = useQuery({
    queryKey: ['admin-meals'],
    queryFn: getAllMealsFromDB,
  });

  const createMutation = useMutation({
    mutationFn: createMeal,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-meals'] });
      setIsFormOpen(false);
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => updateMeal(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-meals'] });
      setIsFormOpen(false);
      setEditingMeal(undefined);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: deleteMeal,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-meals'] });
    },
  });

  const handleSubmit = (data: any) => {
    if (editingMeal) {
      updateMutation.mutate({ id: editingMeal.id, data });
    } else {
      createMutation.mutate(data);
    }
  };

  const handleEdit = (meal: Meal) => {
    setEditingMeal(meal);
    setIsFormOpen(true);
  };

  const handleDelete = (mealId: string) => {
    if (confirm('Are you sure you want to delete this meal?')) {
      deleteMutation.mutate(mealId);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100 mb-2">
            Manage Meals
          </h1>
          <p className="text-gray-600 dark:text-gray-400">
            {meals?.length || 0} meals in database
          </p>
        </div>
        <Button
          onClick={() => {
            setEditingMeal(undefined);
            setIsFormOpen(true);
          }}
        >
          <Plus className="w-4 h-4 mr-2" />
          Add Meal
        </Button>
      </div>

      <Card>
        <AdminMealTable
          meals={meals || []}
          onEdit={handleEdit}
          onDelete={handleDelete}
          isLoading={isLoading}
        />
      </Card>

      <Modal
        isOpen={isFormOpen}
        onClose={() => {
          setIsFormOpen(false);
          setEditingMeal(undefined);
        }}
        title={editingMeal ? 'Edit Meal' : 'Create New Meal'}
        size="xl"
      >
        <AdminMealForm
          meal={editingMeal}
          onSubmit={handleSubmit}
          onCancel={() => {
            setIsFormOpen(false);
            setEditingMeal(undefined);
          }}
          isLoading={createMutation.isPending || updateMutation.isPending}
        />
      </Modal>
    </div>
  );
};

export default AdminMeals;
```

