import { useState, useEffect } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useAppStore } from '../../stores/useAppStore';
import { importMeals } from '../../services/supabase';
import { mealService } from '../../services/mealService';
import Card from '../../components/ui/Card';
import Button from '../../components/ui/Button';
import { Upload, Download, Database } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const AdminImport = () => {
  const { user } = useAppStore();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [jsonData, setJsonData] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (!user?.is_admin) {
      navigate('/');
    }
  }, [user, navigate]);

  const importMutation = useMutation({
    mutationFn: importMeals,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-meals'] });
      setJsonData('');
      alert('Meals imported successfully!');
    },
    onError: (err: any) => {
      setError(err.message || 'Failed to import meals');
    },
  });

  const handleImport = () => {
    setError('');
    try {
      const meals = JSON.parse(jsonData);
      if (!Array.isArray(meals)) {
        setError('JSON must be an array of meals');
        return;
      }
      importMutation.mutate(meals);
    } catch (err) {
      setError('Invalid JSON format');
    }
  };

  const handleLoadLocalData = () => {
    const localMeals = mealService.getAllMeals();
    setJsonData(JSON.stringify(localMeals, null, 2));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setJsonData(event.target?.result as string);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100 mb-2">
          Import Meal Data
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          Bulk import meals from JSON file or local dataset
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-4">
            Quick Actions
          </h2>
          <div className="space-y-3">
            <Button
              onClick={handleLoadLocalData}
              variant="outline"
              fullWidth
            >
              <Database className="w-4 h-4 mr-2" />
              Load Local Dataset
            </Button>
            <label className="block">
              <input
                type="file"
                accept=".json"
                onChange={handleFileUpload}
                className="hidden"
              />
              <Button variant="outline" fullWidth as="span">
                <Upload className="w-4 h-4 mr-2" />
                Upload JSON File
              </Button>
            </label>
          </div>
        </Card>

        <Card>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-4">
            Import Instructions
          </h2>
          <ol className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
            <li className="flex gap-2">
              <span className="font-semibold">1.</span>
              <span>Load local data or upload a JSON file</span>
            </li>
            <li className="flex gap-2">
              <span className="font-semibold">2.</span>
              <span>Review the JSON in the editor below</span>
            </li>
            <li className="flex gap-2">
              <span className="font-semibold">3.</span>
              <span>Click "Import to Database" to save</span>
            </li>
          </ol>
        </Card>
      </div>

      <Card>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100">
            JSON Editor
          </h2>
          <Button
            onClick={handleImport}
            disabled={!jsonData || importMutation.isPending}
            loading={importMutation.isPending}
          >
            Import to Database
          </Button>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-xl text-red-700 dark:text-red-400 text-sm">
            {error}
          </div>
        )}

        <textarea
          value={jsonData}
          onChange={(e) => setJsonData(e.target.value)}
          placeholder="Paste JSON array of meals here..."
          rows={20}
          className="w-full px-4 py-3 bg-gray-50 dark:bg-gray-900 border-2 border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all duration-200 text-gray-900 dark:text-gray-100 placeholder-gray-400 dark:placeholder-gray-500 font-mono text-sm"
        />
      </Card>
    </div>
  );
};

export default AdminImport;
```

